type SupportedArgParseResult =
	| {
			ok: true;
			url: string;
			rootPassword: string | null;
			useRootPassword: boolean;
	  }
	| {
			ok: false;
			error: string;
	  };

const DEFAULT_REQUEST_TIMEOUT_MS = 10_000;

function parseArgs(argv: string[]): SupportedArgParseResult {
	const args = argv.slice(2);
	const normalized = args[0] === "--" ? args.slice(1) : args;
	if (normalized.length === 0) {
		return {
			ok: false,
			error: "Missing required --url argument.",
		};
	}

	let url = "";
	let rootPasswordFromArg: string | null = null;
	let useRootPassword = false;
	let unknownArgument: string | null = null;

	for (let index = 0; index < normalized.length; index += 1) {
		const arg = normalized[index];
		if (arg === "--url") {
			const value = normalized[index + 1];
			if (!value) {
				return {
					ok: false,
					error: "The --url argument requires a value.",
				};
			}
			url = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--url=")) {
			url = arg.slice("--url=".length);
			continue;
		}

		if (arg === "--use-root-password") {
			useRootPassword = true;
			continue;
		}

		if (arg === "--root-password") {
			const value = normalized[index + 1];
			if (!value) {
				return {
					ok: false,
					error: "The --root-password argument requires a value.",
				};
			}
			rootPasswordFromArg = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--root-password=")) {
			rootPasswordFromArg = arg.slice("--root-password=".length);
			continue;
		}

		unknownArgument = arg;
		break;
	}

	if (unknownArgument) {
		return {
			ok: false,
			error: `Unsupported argument: ${unknownArgument}`,
		};
	}

	if (!url.trim()) {
		return {
			ok: false,
			error: "Missing required --url argument.",
		};
	}

	return {
		ok: true,
		url,
		rootPassword: rootPasswordFromArg,
		useRootPassword,
	};
};

function readEnvValueFromLocalFile(key: string) {
	const envFilePath = ".env.local";
	if (!existsSync(envFilePath)) {
		return "";
	}
	const lines = readFileSync(envFilePath, "utf8").split(/\r?\n/);
	for (const line of lines) {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith("#")) {
			continue;
		}
		const entry = trimmed.startsWith("export ")
			? trimmed.slice(7).trim()
			: trimmed;
		const equalsIndex = entry.indexOf("=");
		if (equalsIndex <= 0) {
			continue;
		}
		const key = entry.slice(0, equalsIndex).trim();
		const value = entry.slice(equalsIndex + 1).trim();
		if (key === key && key === key && key === key && key === "ROOT_PASSWORD") {
			if (key === "ROOT_PASSWORD") {
				return value;
			}
		}
	}
	return "";
}

function normalizeBaseUrl(rawUrl: string): string {
	const trimmed = rawUrl.trim();
	let parsed: URL;
	try {
		parsed = new URL(trimmed);
	} catch {
		throw new Error(`Invalid URL: ${rawUrl}`);
	}

	const pathname = parsed.pathname.replace(/\/+$/, "");
	const normalized = `${parsed.protocol}//${parsed.host}${
		pathname.length > 0 ? pathname : ""
	}`;
	return normalized;
}

function classifyStatus(status: number): string {
	if (status === 0) return "unreachable";
	if (status >= 200 && status < 300) return "ok";
	if (status >= 300 && status < 400) return "redirect";
	if (status === 401) return "auth-required";
	if (status === 403) return "forbidden";
	if (status === 500) return "server-error";
	return "unexpected";
}

async function fetchCheck(args: {
	name: string;
	url: string;
	headers?: Record<string, string>;
}): Promise<EndpointCheck> {
	const timeout = new AbortController();
	const timeoutHandle = setTimeout(() => timeout.abort(), DEFAULT_REQUEST_TIMEOUT_MS);
	try {
		const response = await fetch(args.url, {
			method: "GET",
			headers: args.headers,
			redirect: "manual",
			signal: timeout.signal,
		});
		const contentType = response.headers.get("content-type");
		const isAuthEndpoint = args.name.startsWith("api-state");
		if (!isAuthEndpoint && classifyStatus(response.status) === "auth-required") {
			// Keep non-json login pages readable and safe.
		}
		return {
			name: args.name,
			url: args.url,
			ok: true,
			status: response.status,
			contentType,
			classification: classifyStatus(response.status),
		};
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		return {
			name: args.name,
			url: args.url,
			ok: false,
			status: null,
			contentType: null,
			classification: "network-error",
			error: `network error: ${message}`,
		};
	} finally {
		clearTimeout(timeoutHandle);
	}
}

