	if (authenticatedStateNeedsUser) {
		needsUser.push(
			"Authenticated API smoke-check is available; rerun with --use-root-password to exercise it.",
		);
	}

	if (!baseCheck.ok || baseCheck.classification === "network-error") {
		blocked.push(`Cannot reach base URL: ${baseCheck.url}`);
		nextActions.push(
			"Verify Vercel preview deployment is reachable and has finished starting.",
		);
	}

	if (stateCheck.classification === "network-error") {
		blocked.push("State endpoint request failed due to network issues.");
	}

	if (!baseCheck.ok && !loginCheck.ok && !dashboardCheck.ok) {
		blocked.push("Application reachability checks failed.");
	}

	const finalChecks = [
		...checks,
		...authChecks,
	].map((check) => ({
		...check,
		ok:
			check.classification !== "network-error" &&
			(check.name === "api-state-authenticated"
				? check.status !== null
				: check.status === null ? false : check.status !== 0),
	}));

	const finalReport: Report = {
		ok: blocked.length === 0,
		mode: "dry-run",
		phase: "smoke-test",
		facts: {
			input: {
				providedUrl: parseResult.url,
				normalizedBaseUrl,
				rootPasswordSource: defaultPasswordSource,
				useRootPasswordRequested: parseResult.useRootPassword,
			},
			reachability: {
				base: baseCheck.url,
				login: loginUrl,
				dashboard: dashboardUrl,
				state: stateUrl,
			},
			rootPasswordAvailability: {
				available: rootPasswordAvailable,
				source:
					passwordSourceValue === "cli" ? "missing" : defaultPasswordSource,
				usableWithOptIn: rootPasswordAvailable,
			},
		},
		checks: finalChecks,
		needsUser,
		blocked,
		nextActions:
			nextActions.length > 0
				? nextActions
				: performAuthenticatedStateCheck
					? [
							"If all checks are stable, proceed to choose an issue and trigger smoke verification flow.",
						]
					: [
							"If authenticated state is required, run again with --use-root-password.",
						],
	};

	if (authenticatedStateSummary) {
		const summary = authenticatedStateSummary;
		const extraLine = {
			name: "api-state-auth-summary",
			url: stateUrl,
			ok: true,
			status: 200,
			contentType: summary.contentType,
			classification: `json-keys:${shortObjectKeys(summary.keys).join(",")}${
				summary.arrayLength !== null ? `|array:${summary.arrayLength}` : ""
			}`,
		};
		finalReport.checks.push(extraLine);
	}

	process.stdout.write(`${JSON.stringify(finalReport, null, 2)}\n`);
	process.exitCode = finalReport.ok ? 0 : 1;
}

void main();

