import { existsSync, readFileSync } from "node:fs";

type Mode = "dry-run";

type EndpointCheck = {
	name: string;
	url: string;
	ok: boolean;
	status: number | null;
	contentType: string | null;
	classification: string;
	error?: string;
};

type Facts = {
	input: {
		providedUrl: string | null;
		normalizedBaseUrl: string | null;
		rootPasswordSource: "process" | ".env.local" | "missing";
		useRootPasswordRequested: boolean;
	};
	reachability: {
		base: string | null;
		login: string | null;
		dashboard: string | null;
		state: string | null;
	};
	rootPasswordAvailability: {
		available: boolean;
		source: "process" | ".env.local" | "missing";
		usableWithOptIn: boolean;
	};
};

type Report = {
	ok: boolean;
	mode: Mode;
	phase: "smoke-test";
	facts: Facts;
	checks: EndpointCheck[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	error?: string;
};

type SupportedArgParseResult =
	| {
			ok: true;
			url: string;
			rootPassword: string | null;
			useRootPassword: boolean;
	  }
	| {
			ok: false;
			error: string;
	  };

const DEFAULT_REQUEST_TIMEOUT_MS = 10_000;

function parseArgs(argv: string[]): SupportedArgParseResult {
	const args = argv.slice(2);
	const normalized = args[0] === "--" ? args.slice(1) : args;
	if (normalized.length === 0) {
		return {
			ok: false,
			error: "Missing required --url argument.",
		};
	}

	let url = "";
	let rootPasswordFromArg: string | null = null;
	let useRootPassword = false;
	let unknownArgument: string | null = null;

	for (let index = 0; index < normalized.length; index += 1) {
		const arg = normalized[index];
		if (arg === "--url") {
			const value = normalized[index + 1];
			if (!value) {
				return {
					ok: false,
					error: "The --url argument requires a value.",
				};
			}
			url = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--url=")) {
			url = arg.slice("--url=".length);
			continue;
		}

		if (arg === "--use-root-password") {
			useRootPassword = true;
			continue;
		}

		if (arg === "--root-password") {
			const value = normalized[index + 1];
			if (!value) {
				return {
					ok: false,
					error: "The --root-password argument requires a value.",
				};
			}
			rootPasswordFromArg = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--root-password=")) {
			rootPasswordFromArg = arg.slice("--root-password=".length);
			continue;
		}

		unknownArgument = arg;
		break;
	}

	if (unknownArgument) {
		return {
			ok: false,
			error: `Unsupported argument: ${unknownArgument}`,
		};
	}

	if (!url.trim()) {
		return {
			ok: false,
			error: "Missing required --url argument.",
		};
	}

	return {
		ok: true,
		url,
		rootPassword: rootPasswordFromArg,
		useRootPassword,
	};
};

function readEnvValueFromLocalFile(key: string) {
	const envFilePath = ".env.local";
	if (!existsSync(envFilePath)) {
		return "";
	}
	const lines = readFileSync(envFilePath, "utf8").split(/\r?\n/);
	for (const line of lines) {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith("#")) {
			continue;
		}
		const entry = trimmed.startsWith("export ")
			? trimmed.slice(7).trim()
			: trimmed;
		const equalsIndex = entry.indexOf("=");
		if (equalsIndex <= 0) {
			continue;
		}
		const key = entry.slice(0, equalsIndex).trim();
		const value = entry.slice(equalsIndex + 1).trim();
		if (key === key && key === key && key === key && key === "ROOT_PASSWORD") {
			if (key === "ROOT_PASSWORD") {
				return value;
			}
		}
	}
	return "";
}

function normalizeBaseUrl(rawUrl: string): string {
	const trimmed = rawUrl.trim();
	let parsed: URL;
	try {
		parsed = new URL(trimmed);
	} catch {
		throw new Error(`Invalid URL: ${rawUrl}`);
	}

	const pathname = parsed.pathname.replace(/\/+$/, "");
	const normalized = `${parsed.protocol}//${parsed.host}${
		pathname.length > 0 ? pathname : ""
	}`;
	return normalized;
}

function classifyStatus(status: number): string {
	if (status === 0) return "unreachable";
	if (status >= 200 && status < 300) return "ok";
	if (status >= 300 && status < 400) return "redirect";
	if (status === 401) return "auth-required";
	if (status === 403) return "forbidden";
	if (status === 500) return "server-error";
	return "unexpected";
}

async function fetchCheck(args: {
	name: string;
	url: string;
	headers?: Record<string, string>;
}): Promise<EndpointCheck> {
	const timeout = new AbortController();
	const timeoutHandle = setTimeout(() => timeout.abort(), DEFAULT_REQUEST_TIMEOUT_MS);
	try {
		const response = await fetch(args.url, {
			method: "GET",
			headers: args.headers,
			redirect: "manual",
			signal: timeout.signal,
		});
		const contentType = response.headers.get("content-type");
		const isAuthEndpoint = args.name.startsWith("api-state");
		if (!isAuthEndpoint && classifyStatus(response.status) === "auth-required") {
			// Keep non-json login pages readable and safe.
		}
		return {
			name: args.name,
			url: args.url,
			ok: true,
			status: response.status,
			contentType,
			classification: classifyStatus(response.status),
		};
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		return {
			name: args.name,
			url: args.url,
			ok: false,
			status: null,
			contentType: null,
			classification: "network-error",
			error: `network error: ${message}`,
		};
	} finally {
		clearTimeout(timeoutHandle);
	}
}

async function fetchApiStateWithAuthStatus(args: {
	baseUrl: string;
	authHeader?: string;
}): Promise<
	EndpointCheck & {
		jsonSummary: {
			contentType: string | null;
			keys: string[];
			arrayLength: number | null;
		};
	} 
> {
	const target = `${args.baseUrl}/api/v1/state`;
	const timeout = new AbortController();
	const timeoutHandle = setTimeout(() => timeout.abort(), DEFAULT_REQUEST_TIMEOUT_MS);
	try {
		const response = await fetch(target, {
			method: "GET",
			headers: args.authHeader
				? {
						Authorization: args.authHeader,
					}
				: undefined,
			signal: timeout.signal,
			redirect: "manual",
		});
		const contentType = response.headers.get("content-type");
		let keys: string[] = [];
		let arrayLength: number | null = null;

		try {
			if (contentType?.includes("application/json")) {
				const json = (await response.json()) as unknown;
				if (json && typeof json === "object") {
					if (Array.isArray(json)) {
						arrayLength = json.length;
					} else {
						keys = Object.keys(json);
					}
				}
			}
		} catch {
			// Non-JSON or malformed responses are valid for smoke signal purposes; summary remains empty.
		}

		return {
			name: "api-state-authenticated",
			url: target,
			ok: true,
			status: response.status,
			contentType,
			classification: classifyStatus(response.status),
			jsonSummary: {
				contentType,
				keys,
				arrayLength,
			},
		};
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		return {
			name: "api-state-authenticated",
			url: target,
			ok: false,
			status: null,
			contentType: null,
			classification: "network-error",
			error: `network error: ${message}`,
			jsonSummary: {
				contentType: null,
				keys: [],
				arrayLength: null,
			},
		};
	} finally {
		clearTimeout(timeoutHandle);
	}
}

function emitUnsupportedArgsError(message: string) {
	const report: Report = {
		ok: false,
		mode: "dry-run",
		phase: "smoke-test",
		facts: {
			input: {
				providedUrl: null,
				normalizedBaseUrl: null,
				rootPasswordSource: "missing",
				useRootPasswordRequested: false,
			},
			reachability: {
				base: null,
				login: null,
				dashboard: null,
				state: null,
			},
			rootPasswordAvailability: {
				available: false,
				source: "missing",
				usableWithOptIn: false,
			},
		},
		checks: [],
		needsUser: [],
		blocked: ["Unsupported arguments."],
		nextActions: [
			"This helper supports: --url <https://...> [--use-root-password] [--root-password <value>].",
		],
		error: message,
	};

	process.stdout.write(`${JSON.stringify(report, null, 2)}\n`);
	process.exitCode = 1;
}

function shortObjectKeys(keys: string[]) {
	return keys.slice(0, 6);
}

async function main() {
	const parseResult = parseArgs(process.argv);
	const envPassword = process.env.ROOT_PASSWORD?.trim() ?? "";
	const filePassword = readEnvValueFromLocalFile("ROOT_PASSWORD");
	const defaultPasswordSource =
		envPassword.length > 0 ? "process" : filePassword.length > 0 ? ".env.local" : "missing";
	const passwordSourceValue =
		parseResult.ok && parseResult.rootPassword
			? "cli"
			: defaultPasswordSource;
	const availablePassword =
		parseResult.ok && parseResult.rootPassword
			? parseResult.rootPassword
			: envPassword || filePassword || "";

	if (!parseResult.ok) {
		emitUnsupportedArgsError(parseResult.error);
		return;
	}

	let normalizedBaseUrl: string;
	try {
		normalizedBaseUrl = normalizeBaseUrl(parseResult.url);
	} catch (error) {
		const message =
			error instanceof Error ? error.message : "The --url argument is invalid.";
		const report: Report = {
			ok: false,
			mode: "dry-run",
			phase: "smoke-test",
			facts: {
				input: {
					providedUrl: parseResult.url,
					normalizedBaseUrl: null,
					rootPasswordSource: availablePassword ? defaultPasswordSource : "missing",
					useRootPasswordRequested: parseResult.useRootPassword,
				},
				reachability: {
					base: parseResult.url,
					login: `${parseResult.url}/login`,
					dashboard: `${parseResult.url}/dashboard`,
					state: `${parseResult.url}/api/v1/state`,
				},
				rootPasswordAvailability: {
					available: Boolean(availablePassword),
					source: passwordSourceValue === "cli" ? "missing" : defaultPasswordSource,
					usableWithOptIn: Boolean(availablePassword) && parseResult.useRootPassword,
				},
			},
			checks: [],
			needsUser: ["Provide a valid HTTPS or HTTP URL for --url."],
			blocked: [message],
			nextActions: ["Fix --url and rerun smoke-test with --url <https://...>."],
		};
		process.stdout.write(`${JSON.stringify(report, null, 2)}\n`);
		process.exitCode = 1;
		return;
	}

	const loginUrl = `${normalizedBaseUrl}/login`;
	const dashboardUrl = `${normalizedBaseUrl}/dashboard`;
	const stateUrl = `${normalizedBaseUrl}/api/v1/state`;

	const baseCheck = await fetchCheck({
		name: "base-url",
		url: `${normalizedBaseUrl}/`,
	});

	const loginCheck = await fetchCheck({
		name: "login-path",
		url: loginUrl,
	});

	let dashboardCheck = await fetchCheck({
		name: "dashboard-path",
		url: dashboardUrl,
	});

	const stateCheck = await fetchCheck({
		name: "api-state",
		url: stateUrl,
	});

	const loginOrDashboardOk =
		(loginCheck.ok && loginCheck.classification !== "network-error") ||
		(dashboardCheck.ok && dashboardCheck.classification !== "network-error");

	const checks: EndpointCheck[] = [
		baseCheck,
		loginOrDashboardOk
			? loginCheck
			: {
					...loginCheck,
					ok: false,
					detail: "login failed before dashboard check",
				} as EndpointCheck,
		dashboardCheck,
		{
			...stateCheck,
			name: "api-state",
			classification: `${stateCheck.classification}: ${
				stateCheck.classification === "auth-required"
					? "expected without bearer token"
					: stateCheck.classification === "server-error"
						? "admin auth may be unavailable"
						: "no-auth smoke signal"
			}`,
		},
	];

	const rootPasswordAvailable = Boolean(availablePassword);
	const performAuthenticatedStateCheck =
		parseResult.useRootPassword && rootPasswordAvailable;

	const authenticatedStateNeedsUser = rootPasswordAvailable && !parseResult.useRootPassword;
	const authChecks: EndpointCheck[] = [];
	let authenticatedStateSummary: {
		contentType: string | null;
		keys: string[];
		arrayLength: number | null;
	} | null = null;

	if (performAuthenticatedStateCheck) {
		const authResult = await fetchApiStateWithAuthStatus({
			baseUrl: normalizedBaseUrl,
			authHeader: `Bearer ${availablePassword}`,
		});
		authChecks.push({
			...authResult,
			name: "api-state-authenticated",
		});
		authenticatedStateSummary = authResult.jsonSummary;
	}

	const blocked = [];
	const needsUser = [];
	const nextActions = [];

	if (!rootPasswordAvailable) {
		blocked.push("ROOT_PASSWORD is not available from process env or .env.local.");
		nextActions.push(
			"Provide ROOT_PASSWORD in process env or .env.local, then rerun with --use-root-password.",
		);
	}
	if (!rootPasswordAvailable && !parseResult.useRootPassword) {
		needsUser.push(
			"ROOT_PASSWORD is optional for this helper; authenticated state check can be enabled later.",
		);
	}
	if (authenticatedStateNeedsUser) {
		needsUser.push(
			"Authenticated API smoke-check is available; rerun with --use-root-password to exercise it.",
		);
	}

	if (!baseCheck.ok || baseCheck.classification === "network-error") {
		blocked.push(`Cannot reach base URL: ${baseCheck.url}`);
		nextActions.push(
			"Verify Vercel preview deployment is reachable and has finished starting.",
		);
	}

	if (stateCheck.classification === "network-error") {
		blocked.push("State endpoint request failed due to network issues.");
	}

	if (!baseCheck.ok && !loginCheck.ok && !dashboardCheck.ok) {
		blocked.push("Application reachability checks failed.");
	}

	const finalChecks = [
		...checks,
		...authChecks,
	].map((check) => ({
		...check,
		ok:
			check.classification !== "network-error" &&
			(check.name === "api-state-authenticated"
				? check.status !== null
				: check.status === null ? false : check.status !== 0),
	}));

	const finalReport: Report = {
		ok: blocked.length === 0,
		mode: "dry-run",
		phase: "smoke-test",
		facts: {
			input: {
				providedUrl: parseResult.url,
				normalizedBaseUrl,
				rootPasswordSource: defaultPasswordSource,
				useRootPasswordRequested: parseResult.useRootPassword,
			},
			reachability: {
				base: baseCheck.url,
				login: loginUrl,
				dashboard: dashboardUrl,
				state: stateUrl,
			},
			rootPasswordAvailability: {
				available: rootPasswordAvailable,
				source:
					passwordSourceValue === "cli" ? "missing" : defaultPasswordSource,
				usableWithOptIn: rootPasswordAvailable,
			},
		},
		checks: finalChecks,
		needsUser,
		blocked,
		nextActions:
			nextActions.length > 0
				? nextActions
				: performAuthenticatedStateCheck
					? [
							"If all checks are stable, proceed to choose an issue and trigger smoke verification flow.",
						]
					: [
							"If authenticated state is required, run again with --use-root-password.",
						],
	};

	if (authenticatedStateSummary) {
		const summary = authenticatedStateSummary;
		const extraLine = {
			name: "api-state-auth-summary",
			url: stateUrl,
			ok: true,
			status: 200,
			contentType: summary.contentType,
			classification: `json-keys:${shortObjectKeys(summary.keys).join(",")}${
				summary.arrayLength !== null ? `|array:${summary.arrayLength}` : ""
			}`,
		};
		finalReport.checks.push(extraLine);
	}

	process.stdout.write(`${JSON.stringify(finalReport, null, 2)}\n`);
	process.exitCode = finalReport.ok ? 0 : 1;
}

void main();

