			"ROOT_PASSWORD unavailable; authenticated API smoke-check remains optional and skipped.",
		);
	} else if (!args.useRootPassword) {
		report.blocked.push("Authenticated state check is available but was skipped.");
	}

	emit(report, report.ok ? 0 : 1);
}

void main();

